#
# bash recipes/python/fastseqprop_gata2.sh
#
python -m docker_entrypoint \
    --model bpnet \
        --protein 'GATA2' \
    --optimization fastseqprop \
        --learning_rate 0.5 \
        --eta_min 1e-6 \
        --batch_size 32 \
        --rnd_seed 0 \
    --max_seconds 240 \
    --optimization_steps_per_output 5 \
    --proposals_per_round 2 \
    --output_format csv \
    --output_path ./output/python_recipe/fastseqprop_gata2 \
    --start_sequence 
